queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?novels a :Novels .
    ?novels p:Title ?title .
    ?novels p:Character ?character_f .
    FILTER(STR(?character_f) = "John Smith")
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?shortstories a :ShortStories .
    ?shortstories p:Title ?title .
    ?shortstories p:Character ?character_f .
    FILTER(STR(?character_f) = "John Smith")
    BIND(?title AS ?o0)
  }
}

